parameters.jsCode:
// ---- CONFIG ----
const BATCH_SIZE = 5;

// ---- PARSE AI OUTPUT ----
const rawText = $input.first().json.text;

const blocks = rawText
  .split(/\n\s*\n+/)
  .map(b => b.trim())
  .filter(b => b.length > 0 && b.startsWith('ASIN'));

const products = blocks.map(block => {
  const getField = (label) => {
    const regex = new RegExp(`${label}\\s*:\\s*(.+)`, 'i');
    const match = block.match(regex);
    return match ? match[1].trim() : null;
  };
  const asin = getField('ASIN');
  const origPriceRaw = getField('Original Price');
  const avgSellerPriceRaw = getField('Average Seller Price');
  const ratingLine = getField('Average Seller Rating');
  const verdictRaw = getField('Competition Verdict');
  const reason = getField('Reason');
  const origPrice = origPriceRaw ? parseFloat(origPriceRaw.replace(/[^0-9.]/g, '')) : null;
  const avgSellerPrice = avgSellerPriceRaw ? parseFloat(avgSellerPriceRaw.replace(/[^0-9.]/g, '')) : null;
  let avgRating = null;
  let sellerCount = null;
  if (ratingLine) {
    const ratingMatch = ratingLine.match(/([\d.]+)★/);
    const sellerMatch = ratingLine.match(/\((\d+)\s*sellers?\)/i);
    avgRating = ratingMatch ? parseFloat(ratingMatch[1]) : null;
    sellerCount = sellerMatch ? parseInt(sellerMatch[1]) : null;
  }
  const isMissingData = sellerCount === 0 || avgSellerPrice === 0 || avgRating === 0;
  const verdictClean = verdictRaw ? verdictRaw.replace(/[^\w\s—-]/g, '').trim() : 'Unknown';
  let verdictEmoji = '⚪';
  if (!isMissingData) {
    if (/low/i.test(verdictClean)) verdictEmoji = '🟢';
    else if (/medium/i.test(verdictClean)) verdictEmoji = '🟡';
    else if (/high/i.test(verdictClean)) verdictEmoji = '🟠';
    else if (/pass/i.test(verdictClean)) verdictEmoji = '🔴';
  }
  return {
    asin, origPrice, avgSellerPrice, avgRating, sellerCount,
    verdict: isMissingData ? 'No Data' : verdictClean,
    verdictEmoji,
    reason: reason || 'No reason provided.',
    isMissingData
  };
});
// ---- FORMAT EACH PRODUCT ----
function formatProduct(p) {
  const price = p.origPrice !== null ? ('$' + p.origPrice.toFixed(2)) : 'N/A';
  const avgPrice = p.isMissingData ? 'N/A (no seller data)' : ('$' + p.avgSellerPrice.toFixed(2));
  const rating = p.isMissingData ? 'N/A' : (p.avgRating.toFixed(2) + '★');
  const sellers = p.sellerCount !== null ? p.sellerCount : 'N/A';
  return 'ASIN: ' + p.asin + '\n' +
    'Original Price: ' + price + '\n' +
    'Average Seller Price: ' + avgPrice + '\n' +
    'Average Seller Rating: ' + rating + ' (' + sellers + ' sellers)\n' +
    'Competition Verdict: ' + p.verdictEmoji + ' ' + p.verdict + '\n' +
    'Reason: ' + p.reason;
}

// ---- SPLIT INTO BATCHES ----
const batches = [];
for (let i = 0; i < products.length; i += BATCH_SIZE) {
  batches.push(products.slice(i, i + BATCH_SIZE));
}
const totalBatches = batches.length;

// ---- BUILD ONE MESSAGE PER BATCH ----
const outputItems = batches.map(function(batch, index) {
  const batchLines = batch.map(formatProduct).join('\n\n');
  const header = totalBatches > 1
    ? ('📊 Competition Report (Part ' + (index + 1) + ' of ' + totalBatches + ') — products ' + (index * BATCH_SIZE + 1) + '-' + (index * BATCH_SIZE + batch.length) + ' of ' + products.length)
    : ('📊 Competition Report — ' + products.length + ' products');
  return {
    json: {
      formattedReport: header + '\n\n' + batchLines,
      batchNumber: index + 1,
      totalBatches,
      productsInBatch: batch.length
    }
  };
});

return outputItems;
